import { convertLezerTree } from './tree-conversion.js';
import type { FilterFieldProps } from '../../FilterField.types.js';
import { getNumberParser } from '../../parser/getNumberParser.js';
import { parser } from '../../parser/parser.js';
import type { FilterFieldTree } from '../../types/tree-nodes.js';
import type {
  FilterFieldCustomTypes,
  FilterFieldValidatorMap,
} from '../../types/validation.js';
import { toInternalValidatorMap } from '../../utils/validation-utils/normalize-validator-map.js';

/**
 * Conversion util that converts a string into a filter field tree.
 * @param filterString - Input string
 * @param options - Conversion options
 * @public
 */
export function convertStringToFilterFieldTree(
  filterString: string,
  options?: {
    /** Validators to restrict allowed keys and their operators. */
    validatorMap?: FilterFieldValidatorMap;
    /** Map of custom types and their validation functions. */
    customTypes?: FilterFieldCustomTypes;
    /** Config to enable new nodes in the FilterFieldTree. */
    parserConfig?: FilterFieldProps['parserConfig'];
  },
): { tree: FilterFieldTree; isValid: boolean };

/**
 * Conversion util that converts a string into a filter field tree.
 * @param filterString - Input string
 * @param validatorMap - Validators to restrict allowed keys and their operators
 * @param parserConfig - Config to enable new nodes in the FilterFieldTree
 * @public
 * @deprecated Use the options object overload instead, passing a `ConvertStringToFilterFieldTreeOptions` object as the second argument.
 */
// DEPRECATION: [APPDEV-16735] BREAKING-CHANGE: Remove depercated convertStringToFilterFieldTree signature.
export function convertStringToFilterFieldTree(
  filterString: string,
  validatorMap?: FilterFieldValidatorMap,
  parserConfig?: FilterFieldProps['parserConfig'],
): { tree: FilterFieldTree; isValid: boolean };

/**
 * @internal
 */
export function convertStringToFilterFieldTree(
  filterString: string,
  optionsOrValidatorMap?:
    | {
        /** Validators to restrict allowed keys and their operators. */
        validatorMap?: FilterFieldValidatorMap;
        /** Custom types to restrict allowed values in the validator map. */
        customTypes?: FilterFieldCustomTypes;
        /** Config to enable new nodes in the FilterFieldTree. */
        parserConfig?: FilterFieldProps['parserConfig'];
      }
    | FilterFieldValidatorMap,
  parserConfig?: FilterFieldProps['parserConfig'],
): { tree: FilterFieldTree; isValid: boolean } {
  let validatorMap: FilterFieldValidatorMap | undefined;
  let customTypes: FilterFieldCustomTypes | undefined = undefined;
  let _parserConfig: FilterFieldProps['parserConfig'];

  if (isConvertStringToFilterFieldTreeOptions(optionsOrValidatorMap)) {
    validatorMap = optionsOrValidatorMap?.validatorMap;
    customTypes = optionsOrValidatorMap?.customTypes;
    _parserConfig = optionsOrValidatorMap?.parserConfig;
  } else {
    validatorMap = optionsOrValidatorMap;
    _parserConfig = parserConfig;
  }

  const numberParser = getNumberParser();
  const parsedTree = parser.parse(filterString);

  const { tree, isValid } = convertLezerTree({
    tree: parsedTree,
    numberParser,
    doc: filterString,
    internalValidatorMap: toInternalValidatorMap(validatorMap),
    customTypes,
    parserConfig: _parserConfig,
  });

  return { tree, isValid };
}

function isConvertStringToFilterFieldTreeOptions(value: unknown): value is {
  /** Validators to restrict allowed keys and their operators. */
  validatorMap?: FilterFieldValidatorMap;
  /** Custom types to restrict allowed values in the validator map. */
  customTypes?: FilterFieldCustomTypes;
  /** Config to enable new nodes in the FilterFieldTree. */
  parserConfig?: FilterFieldProps['parserConfig'];
} {
  if (typeof value !== 'object' || value === null || Array.isArray(value)) {
    return false;
  }
  return (
    'validatorMap' in value || 'customTypes' in value || 'parserConfig' in value
  );
}
